/**
 * Initialize Envelope (TVPX__20)
 * Bulletproof normalization for downstream multi-LLM pipeline.
 */
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

function toBool(value, fallback = false) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const normalized = String(value).trim().toLowerCase();
  if (!normalized) return fallback;
  if (['1', 'true', 'yes', 'y', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'no', 'n', 'off'].includes(normalized)) return false;
  return fallback;
}

function clampInt(value, fallback, min, max) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(min, Math.min(Math.round(n), max));
}

const incoming = $json || {};
const now = new Date().toISOString();

const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};
const traceSeed = JSON.stringify(incoming).slice(0, 5000) + '::' + now;

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: baseCtx.trace_id || ('tvpx_' + fnv1a(traceSeed)),
  trigger_mode: baseCtx.trigger_mode || incoming.trigger_mode || 'internal',
  route_mode: baseCtx.route_mode || incoming.route_mode || 'concept_forge',
  received_at: now,
  crawl_run_id: String(incoming.crawl_run_id || baseCtx.crawl_run_id || '').trim(),
  source_id: String(incoming.source_id || baseCtx.source_id || '').trim(),
  max_fragments_for_llm: clampInt(baseCtx.max_fragments_for_llm ?? incoming.max_fragments_for_llm, 10, 3, 16),
  max_chars_per_fragment_for_llm: clampInt(baseCtx.max_chars_per_fragment_for_llm ?? incoming.max_chars_per_fragment_for_llm, 1400, 600, 2200),
  target_abstraction_min: Number(baseCtx.target_abstraction_min || incoming.target_abstraction_min || 5.8),
  target_abstraction_max: Number(baseCtx.target_abstraction_max || incoming.target_abstraction_max || 6.8),
  autonomous_run_limit: clampInt(baseCtx.autonomous_run_limit ?? incoming.autonomous_run_limit, 3, 1, 12),
  min_fragments_per_run: clampInt(baseCtx.min_fragments_per_run ?? incoming.min_fragments_per_run, 3, 1, 20),
  autonomous_scan_limit: clampInt(baseCtx.autonomous_scan_limit ?? incoming.autonomous_scan_limit, 1500, 50, 5000),
  allow_reprocess_runs: toBool(baseCtx.allow_reprocess_runs ?? incoming.allow_reprocess_runs, false),
};

const source = (incoming.source && typeof incoming.source === 'object') ? incoming.source : {};
const providedFragments = Array.isArray(incoming.fragments)
  ? incoming.fragments
  : (Array.isArray(incoming.provided_fragments) ? incoming.provided_fragments : []);

return [{
  json: {
    ctx,
    source,
    input: incoming.input || incoming,
    carry: incoming.carry || {},
    provided_fragments: providedFragments,
  },
}];

/**
 * Build Candidate Run Packets
 * Hydrates the same crawl-run context TVPX__10 would have handed downstream.
 */
function toInt(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? Math.round(n) : fallback;
}

function stampOf(row) {
  return String(
    row.completed_at ||
    row.started_at ||
    row.updated_at ||
    row.created_at ||
    ''
  ).trim();
}

const base = $items('Initialize Envelope')[0]?.json || {};
const baseCtx = (base.ctx && typeof base.ctx === 'object') ? base.ctx : {};
const baseSource = (base.source && typeof base.source === 'object') ? base.source : {};
const providedFragments = Array.isArray(base.provided_fragments) ? base.provided_fragments : [];
const requestedRunId = String(baseCtx.crawl_run_id || '').trim();
const requestedSourceId = String(baseCtx.source_id || '').trim();
const maxRuns = Math.max(1, Math.min(Number(baseCtx.autonomous_run_limit || 3), 12));
const minFragmentsPerRun = Math.max(1, Math.min(Number(baseCtx.min_fragments_per_run || 3), 20));
const allowReprocess = Boolean(baseCtx.allow_reprocess_runs);

const runRows = $items('Get Candidate Crawl Runs')
  .map((item) => item.json || {})
  .filter((row) => row && Object.keys(row).length)
  .map((row) => ({
    crawl_run_id: String(row.crawl_run_id || '').trim(),
    trace_id: String(row.trace_id || '').trim(),
    source_id: String(row.source_id || '').trim(),
    trigger_mode: String(row.trigger_mode || '').trim(),
    status: String(row.status || '').trim().toLowerCase(),
    started_at: String(row.started_at || '').trim(),
    completed_at: String(row.completed_at || '').trim(),
    fragment_count: toInt(row.fragment_count, 0),
    page_count: toInt(row.page_count, 0),
    raw_item_count: toInt(row.raw_item_count, 0),
  }))
  .filter((row) => row.crawl_run_id);

const existingSceneSeedRows = $items('Get Existing Scene Seeds')
  .map((item) => item.json || {})
  .filter((row) => row && Object.keys(row).length);

const consumedRunIds = allowReprocess
  ? new Set()
  : new Set(
      existingSceneSeedRows
        .map((row) => String(row.crawl_run_id || '').trim())
        .filter(Boolean)
    );

if (providedFragments.length) {
  const inferredRunId = requestedRunId || String(providedFragments[0]?.crawl_run_id || '').trim();
  const inferredSourceId = requestedSourceId || String(providedFragments[0]?.source_id || '').trim();

  return [{
    json: {
      ctx: {
        ...baseCtx,
        crawl_run_id: inferredRunId,
        source_id: inferredSourceId,
      },
      source: baseSource,
      provided_fragments: providedFragments,
      candidate_run: {
        crawl_run_id: inferredRunId,
        source_id: inferredSourceId,
        trace_id: String(baseCtx.trace_id || '').trim(),
        trigger_mode: String(baseCtx.trigger_mode || 'internal').trim(),
        status: 'provided_fragments',
        fragment_count: providedFragments.length,
      },
      candidate_debug: {
        selection_mode: 'provided_fragments',
        requested_crawl_run_id: requestedRunId || null,
        requested_source_id: requestedSourceId || null,
        selected_run_count: 1,
        selected_rank: 1,
        run_rows_scanned: runRows.length,
        existing_scene_seed_rows: existingSceneSeedRows.length,
        allow_reprocess_runs: allowReprocess,
      },
    },
  }];
}

let selectedRuns = [];
if (requestedRunId) {
  const exact = runRows.find((row) => row.crawl_run_id === requestedRunId);
  selectedRuns = [exact || {
    crawl_run_id: requestedRunId,
    trace_id: String(baseCtx.trace_id || '').trim(),
    source_id: requestedSourceId,
    trigger_mode: String(baseCtx.trigger_mode || 'internal').trim(),
    status: 'requested_manual',
    fragment_count: 0,
    page_count: 0,
    raw_item_count: 0,
    started_at: '',
    completed_at: '',
  }];
} else {
  selectedRuns = runRows
    .filter((row) => !requestedSourceId || row.source_id === requestedSourceId)
    .filter((row) => !row.status || ['completed', 'ready', 'done'].includes(row.status))
    .filter((row) => allowReprocess || !consumedRunIds.has(row.crawl_run_id))
    .filter((row) => row.fragment_count >= minFragmentsPerRun)
    .sort((a, b) => {
      if (b.fragment_count !== a.fragment_count) return b.fragment_count - a.fragment_count;
      return stampOf(b).localeCompare(stampOf(a));
    })
    .slice(0, maxRuns);
}

if (!selectedRuns.length) {
  return [{
    json: {
      ctx: {
        ...baseCtx,
        crawl_run_id: requestedRunId,
        source_id: requestedSourceId,
      },
      source: baseSource,
      provided_fragments: [],
      candidate_run: null,
      candidate_debug: {
        selection_mode: requestedRunId ? 'requested_run' : 'crawl_run_ledger',
        requested_crawl_run_id: requestedRunId || null,
        requested_source_id: requestedSourceId || null,
        selected_run_count: 0,
        selected_rank: 0,
        run_rows_scanned: runRows.length,
        existing_scene_seed_rows: existingSceneSeedRows.length,
        allow_reprocess_runs: allowReprocess,
      },
    },
  }];
}

return selectedRuns.map((run, index) => ({
  json: {
    ctx: {
      ...baseCtx,
      trace_id: String(run.trace_id || baseCtx.trace_id || '').trim() || baseCtx.trace_id,
      trigger_mode: String(run.trigger_mode || baseCtx.trigger_mode || 'internal').trim(),
      crawl_run_id: String(run.crawl_run_id || '').trim(),
      source_id: String(run.source_id || requestedSourceId || '').trim(),
    },
    source: baseSource,
    provided_fragments: [],
    candidate_run: run,
    candidate_debug: {
      selection_mode: requestedRunId ? 'requested_run' : 'crawl_run_ledger',
      requested_crawl_run_id: requestedRunId || null,
      requested_source_id: requestedSourceId || null,
      selected_run_count: selectedRuns.length,
      selected_rank: index + 1,
      run_rows_scanned: runRows.length,
      existing_scene_seed_rows: existingSceneSeedRows.length,
      allow_reprocess_runs: allowReprocess,
    },
  },
}));

/**
 * Prepare Active Candidate Run
 * Materializes the active split-in-batches item onto $json for downstream DataTable lookups.
 */
const item = $json || {};
const ctx = (item.ctx && typeof item.ctx === 'object') ? item.ctx : {};
const source = (item.source && typeof item.source === 'object') ? item.source : {};

return [{
  json: {
    ctx,
    source,
    provided_fragments: Array.isArray(item.provided_fragments) ? item.provided_fragments : [],
    candidate_run: item.candidate_run || null,
    candidate_debug: item.candidate_debug || null,
  },
}];

/**
 * Attach Source To Candidate
 * Restores the active candidate packet after source lookup and tolerates a missing registry row.
 */
const candidate = $items('Prepare Active Candidate Run')[0]?.json || {};
const sourceRows = $input.all().map((item) => item.json || {}).filter((row) => row && Object.keys(row).length);

const ctx = (candidate.ctx && typeof candidate.ctx === 'object') ? candidate.ctx : {};
const candidateSource = (candidate.source && typeof candidate.source === 'object') ? candidate.source : {};
const source = sourceRows[0]
  || (Object.keys(candidateSource).length ? candidateSource : (ctx.source_id ? { source_id: ctx.source_id } : {}));

return [{
  json: {
    ...candidate,
    source,
  },
}];

/**
 * Reattach Context After Fragments
 * Rebuilds the runtime packet from the active candidate plus the fetched fragment rows.
 */
const envelope = $items('Initialize Envelope')[0]?.json || {};
const base = $items('Attach Source To Candidate')[0]?.json || {};
const inputRows = $input.all().map((item) => item.json || {});

const fragments = inputRows.filter((row) => row && String(row.fragment_id || row.id || row.dt_row_id || '').trim());
const providedFragments = Array.isArray(base.provided_fragments)
  ? base.provided_fragments
  : (Array.isArray(envelope.provided_fragments) ? envelope.provided_fragments : []);

const ctx = (base.ctx && typeof base.ctx === 'object')
  ? base.ctx
  : ((envelope.ctx && typeof envelope.ctx === 'object') ? envelope.ctx : {});

const baseSource = (base.source && typeof base.source === 'object') ? base.source : {};
const envelopeSource = (envelope.source && typeof envelope.source === 'object') ? envelope.source : {};
const source = Object.keys(baseSource).length ? baseSource : envelopeSource;

return [{
  json: {
    ctx,
    source,
    fragments: fragments.length ? fragments : providedFragments,
    candidate_run: base.candidate_run || null,
    candidate_debug: base.candidate_debug || null,
  },
}];

/** Build No Fragments Reject */
const base = $json || {};
const ctx = (base.ctx && typeof base.ctx === 'object') ? base.ctx : {};
const now = new Date().toISOString();
return [{
  json: {
    ...base,
    reject: {
      reject_id: 'tvpx_rej_' + (ctx.trace_id || 'missing') + '_no_fragments',
      trace_id: ctx.trace_id,
      stage_name: 'concept_forge_ingress',
      rejection_reason: 'No eligible fragments were found for concept forging. The selected crawl run may be empty, already consumed, or missing clean fragments.',
      raw_output_json: JSON.stringify({
        crawl_run_id: ctx.crawl_run_id,
        source_id: ctx.source_id,
        candidate_debug: base.candidate_debug || null,
      }),
      created_at: now,
    },
  },
}];

/**
 * Assemble Fragment Bundle
 * Selects high-signal fragments aligned with The Velvet Paradox creative DNA.
 */
function clean(s) {
  return String(s || '').replace(/\r/g, '').replace(/[\t ]+/g, ' ').trim();
}
function clip(s, n) {
  const t = clean(s);
  return t.length > n ? t.slice(0, n) + '…' : t;
}
const base = $json;
const ctx = base.ctx;
const source = base.source || {};
const frags = Array.isArray(base.fragments) ? base.fragments : [];

const SIGNAL = ['pressure','fracture','collapse','repair','restraint','rupture','erosion','threshold','damage','bruise','stain','residue','seep','crack','buckle','warp','misalign','aftermath','tension','constraint','weight','drift','fragile','ritual','memory','identity','veil','shadow','fog','silence','ruin','relic','static','paradox'];
function scoreFrag(t) {
  const s = t.toLowerCase();
  let score = 0;
  for (const w of SIGNAL) if (s.includes(w)) score += 1;
  if (/(stone|plaster|velvet|metal|dust|smoke|haze|wet|rust|cloth|feather|fur|wax|candle|mirror|arch|stair)/i.test(t)) score += 3;
  if (t.length > 500) score += 1;
  return score;
}

const normalized = frags.map(f => {
  const cleaned = clean(f.cleaned_text || f.text || f.raw_text || '');
  return {
    fragment_id: String(f.fragment_id || f.id || f.dt_row_id || '').trim(),
    page_url: String(f.page_url || f.url || '').trim(),
    page_title: String(f.page_title || f.title || '').trim(),
    cleaned_text: cleaned
  };
}).filter(x => x.cleaned_text);

normalized.sort((a,b) => scoreFrag(b.cleaned_text) - scoreFrag(a.cleaned_text));

const takeN = Math.max(3, Math.min(Number(ctx.max_fragments_for_llm || 10), 16));
const maxChars = Math.max(600, Math.min(Number(ctx.max_chars_per_fragment_for_llm || 1400), 2200));

const picked = normalized.slice(0, takeN).map(x => ({
  fragment_id: x.fragment_id,
  page_url: x.page_url,
  page_title: x.page_title,
  excerpt: clip(x.cleaned_text, maxChars)
}));

const excerptBlock = picked.map((p, i) => {
  const head = `[#${i+1}] ${p.page_title || 'Untitled'} | ${p.page_url || ''}`.trim();
  return `${head}\n${p.excerpt}`;
}).join('\n\n---\n\n');

return [{
  json: {
    ctx,
    source,
    bundle: {
      source_id: ctx.source_id,
      crawl_run_id: ctx.crawl_run_id,
      fragment_ids: picked.map(p => p.fragment_id).filter(Boolean),
      excerpt_block: excerptBlock
    }
  }
}];

const base = $items('Assemble Fragment Bundle')[0]?.json;
if (!base) throw new Error('TVPX__20: missing Assemble Fragment Bundle payload.');

const rows = $input.all().map((i) => i.json || {}).filter(Boolean);

const archetypes = rows.map((r) => ({
  archetype_id: String(r.archetype_id || '').trim(),
  archetype_name: String(r.archetype_name || '').trim(),
  allowed_text_role: String(r.allowed_text_role || 'none').trim(),
  subject_mode_bias_json: String(r.subject_mode_bias_json || '[]'),
  camera_dna: String(r.camera_dna || '').trim(),
  palette_dna: String(r.palette_dna || '').trim(),
  material_dna_json: String(r.material_dna_json || '[]'),
  surreal_lift_rules_json: String(r.surreal_lift_rules_json || '[]'),
  negative_space_dna: String(r.negative_space_dna || '').trim(),
  forbidden_tells_json: String(r.forbidden_tells_json || '[]'),
  notes: String(r.notes || '').trim(),
})).filter((x) => x.archetype_id);

return [{
  json: {
    ...base,
    archetype_registry_json: JSON.stringify(archetypes, null, 2),
  },
}];

