function parseStrictJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? raw?.body?.output_text ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('TVPX parser: empty LLM output.');

  const candidates = [
    text,
    text.replace(/\`\`\`json\s*/gi, '').replace(/\`\`\`/g, '').trim(),
  ];

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');

    return JSON.parse(slice);
  }

  throw new Error('TVPX parser: could not locate valid JSON.');
}

const base = $items('Attach Archetype Registry')[0]?.json;
if (!base) throw new Error('TVPX parser: base node "Attach Archetype Registry" missing.');

const parsed = parseStrictJson($json);

return [{
  json: {
    ...base,
    latent_tension: parsed,
  },
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const ctx = j.ctx || {};
const bundle = j.bundle || {};
const latent = j.latent_tension || {};
const now = new Date().toISOString();
const fragmentIds = Array.isArray(bundle.fragment_ids) ? bundle.fragment_ids.filter(Boolean) : [];

const tensionId = `tvpx_tn_${fnv1a([
  ctx.trace_id,
  ctx.crawl_run_id,
  ctx.source_id,
  fragmentIds.join(','),
].join('::'))}`;

return [{
  json: {
    ...j,
    latent_tension_row: {
      tension_id: tensionId,
      trace_id: String(ctx.trace_id || '').trim(),
      crawl_run_id: String(ctx.crawl_run_id || '').trim(),
      source_id: String(ctx.source_id || '').trim(),
      fragment_ids_json: JSON.stringify(fragmentIds),
      latent_tensions_json: JSON.stringify(Array.isArray(latent.latent_tensions) ? latent.latent_tensions : []),
      relational_modes_json: JSON.stringify(Array.isArray(latent.relational_modes) ? latent.relational_modes : []),
      ritual_forms_json: JSON.stringify(Array.isArray(latent.ritual_forms) ? latent.ritual_forms : []),
      environmental_pressures_json: JSON.stringify(Array.isArray(latent.environmental_pressures) ? latent.environmental_pressures : []),
      forbidden_literal_carryovers_json: JSON.stringify(Array.isArray(latent.forbidden_literal_carryovers) ? latent.forbidden_literal_carryovers : []),
      status: 'active',
      created_at: now,
      updated_at: now,
    },
  },
}];

